;=======================================================================================
; UI/FCM tile and glyph data.
;
; Compiles standalone into the `uitiles` asset (loaded from disk at boot). The
; payload is laid out at the offsets in shared/ui_tile_layout.asm; tileloader.asm
; DMAs from those same offsets. The ui_glyph_* bitmaps MUST stay in
; UI_TEXT_A..UI_TEXT_COLON order, since the index/offsets are generated by loops.
;
; Record format:
;   .word tile id
;   .word payload size
;   .byte payload bytes
;=======================================================================================

        .cpu "45gs02"
        .include "../platform.asm"
        .include "../shared/ui_tile_layout.asm"

        * = $6800

ui_tiles_start:

UI_TILE_INDEX_ENTRY .macro index, size, width_cells, height_cells, offset
        .word \index
        .word \size
        .byte \width_cells, \height_cells
        .word \offset
.endmacro

UI_TEXT_BG = $0E
UI_TEXT_FG = $08

UI_TEXT_ROW .macro p0, p1, p2, p3, p4
        .byte UI_TEXT_BG, \p0, \p1, \p2, \p3, \p4, UI_TEXT_BG, UI_TEXT_BG
.endmacro

UI_TILE_RECORD .macro index
.endmacro

ui_tile_index:
        #UI_TILE_INDEX_ENTRY UI_TILE_PANEL, UI_TILE_CHAR_SIZE, 1, 1, UI_ASSET_OFF_PANEL
        #UI_TILE_INDEX_ENTRY UI_TILE_MENU, UI_TILE_CHAR_SIZE, 1, 1, UI_ASSET_OFF_MENU
        #UI_TILE_INDEX_ENTRY UI_TILE_STATUS_LIGHT, UI_TILE_CHAR_SIZE, 1, 1, UI_ASSET_OFF_STATUS_LIGHT
        #UI_TILE_INDEX_ENTRY UI_TILE_STATUS_DARK, UI_TILE_CHAR_SIZE, 1, 1, UI_ASSET_OFF_STATUS_DARK
        #UI_TILE_INDEX_ENTRY UI_TILE_FRAME, UI_TILE_CHAR_SIZE, 1, 1, UI_ASSET_OFF_FRAME
        #UI_TILE_INDEX_ENTRY UI_TILE_BOTTOM, UI_TILE_CHAR_SIZE, 1, 1, UI_ASSET_OFF_BOTTOM
.for i = 0, i < UI_TEXT_COUNT, i = i + 1
        #UI_TILE_INDEX_ENTRY (UI_TEXT_A + i), UI_TILE_CHAR_SIZE, 1, 1, UI_TEXT_OFF_BASE + i * UI_TILE_CHAR_SIZE
.next
.for i = 0, i < UI_BTN_COUNT, i = i + 1
        #UI_TILE_INDEX_ENTRY (UI_BTN_BASE + i * 4), UI_BTN_TILE_SIZE, UI_BTN_CELLS_X, UI_BTN_CELLS_Y, UI_BTN_OFF_BASE + i * UI_BTN_TILE_SIZE
.next

#UI_TILE_RECORD UI_TILE_PANEL
ui_data_panel:
        .fill 64, $0C

#UI_TILE_RECORD UI_TILE_MENU
ui_data_menu:
        .fill 64, $0E

#UI_TILE_RECORD UI_TILE_STATUS_LIGHT
ui_data_status_light:
        .fill 64, $0C

#UI_TILE_RECORD UI_TILE_STATUS_DARK
ui_data_status_dark:
        .fill 64, $0C

#UI_TILE_RECORD UI_TILE_FRAME
ui_data_frame:
        .fill 64, $08

#UI_TILE_RECORD UI_TILE_BOTTOM
ui_data_bottom:
        .byte $08,$08,$08,$08,$08,$08,$08,$08
        .byte $0F,$0F,$0F,$0F,$0F,$0F,$0F,$0F
        .byte $0F,$0F,$0F,$0F,$0F,$0F,$0F,$0F
        .byte $0F,$0F,$0F,$0F,$0F,$0F,$0F,$0F
        .byte $0F,$0F,$0F,$0F,$0F,$0F,$0F,$0F
        .byte $0F,$0F,$0F,$0F,$0F,$0F,$0F,$0F
        .byte $0F,$0F,$0F,$0F,$0F,$0F,$0F,$0F
        .byte $08,$08,$08,$08,$08,$08,$08,$08

